class Student:
    def __init__(self, name, scores):
        self.name = name
        self.scores = scores

    def average(self):
        return sum(self.scores) / len(self.scores)


name, n = input().split()
scores = list(map(int, input().split()))

s = Student(name, scores)
print(f"{s.name}의 평균: {s.average():.1f}")

class Account:
    def __init__(self, balance):
        self.balance = balance

    def deposit(self, amount):
        self.balance += amount

    def withdraw(self, amount):
        if amount <= self.balance:  # 잔액이 충분할 때만 출금
            self.balance -= amount


balance, m = map(int, input().split())
acc = Account(balance)
for _ in range(m):
    op, amount = input().split()
    amount = int(amount)
    if op == 'D':
        acc.deposit(amount)
    else:
        acc.withdraw(amount)

print(acc.balance)

import math

class Point:
    def __init__(self, x, y):
        self.x = x
        self.y = y

    def distance(self, other):
        return math.sqrt((other.x - self.x) ** 2 + (other.y - self.y) ** 2)


x1, y1, x2, y2 = map(int, input().split())
p1, p2 = Point(x1, y1), Point(x2, y2)

print(f"{p1.distance(p2):.2f}")

class Rectangle:
    def __init__(self, width, height):
        self.width = width
        self.height = height

    def perimeter(self):
        return 2 * (self.width + self.height)

    def area(self):
        return self.width * self.height


w, h = map(int, input().split())
r = Rectangle(w, h)

print(r.perimeter(), r.area())

class Inventory:
    def __init__(self):
        self.items = {}

    def add(self, name, qty):
        self.items[name] = qty

    def query(self, name):
        return self.items.get(name, 0)  # 없으면 기본값 0


n = int(input())
inv = Inventory()
for _ in range(n):
    name, qty = input().split()
    inv.add(name, int(qty))

query = input()
print(inv.query(query))

class Stack:
    def __init__(self):
        self.data = []

    def push(self, value):
        self.data.append(value)

    def pop(self):
        if self.data:
            return self.data.pop()  # 리스트의 맨 뒤 = 스택의 맨 위
        return 'empty'


m = int(input())
stack = Stack()
results = []
for _ in range(m):
    cmd = input().split()
    if cmd[0] == 'push':
        stack.push(cmd[1])
    else:
        results.append(stack.pop())

print('\n'.join(results))

from collections import deque

class Queue:
    def __init__(self):
        self.data = deque()

    def enqueue(self, value):
        self.data.append(value)

    def dequeue(self):
        if self.data:
            return self.data.popleft()  # 맨 앞에서 꺼낸다 (먼저 들어온 것이 먼저 나감)
        return 'empty'


m = int(input())
q = Queue()
results = []
for _ in range(m):
    cmd = input().split()
    if cmd[0] == 'enqueue':
        q.enqueue(cmd[1])
    else:
        results.append(q.dequeue())

print('\n'.join(results))

class Circle:
    def __init__(self, r):
        self.r = r

    def area(self):
        return 3.14 * self.r * self.r


class Rectangle:
    def __init__(self, w, h):
        self.w = w
        self.h = h

    def area(self):
        return self.w * self.h


n = int(input())
shapes = []
for _ in range(n):
    parts = input().split()
    if parts[0] == 'C':
        shapes.append(Circle(int(parts[1])))
    else:
        shapes.append(Rectangle(int(parts[1]), int(parts[2])))

# 같은 방식(area())으로 모든 도형의 넓이를 비교
best = 0
for i in range(1, n):
    if shapes[i].area() > shapes[best].area():
        best = i

print(best)
